import React, { useRef, useState } from 'react';
import { motion } from 'framer-motion';

export default function UploadDropzone({ preview, fileName, onFileSelect, onRemove, onSubmit, isLoading, error }) {
  const inputRef = useRef(null);
  const [dragActive, setDragActive] = useState(false);

  const updateFile = async (file) => {
    if (!file || !file.type.startsWith('image/')) return;
    const reader = new FileReader();
    reader.onload = () => {
      onFileSelect(file, reader.result);
    };
    reader.readAsDataURL(file);
  };

  const handleDrop = (event) => {
    event.preventDefault();
    setDragActive(false);
    updateFile(event.dataTransfer.files[0]);
  };

  const handleChange = (event) => {
    updateFile(event.target.files[0]);
  };

  return (
    <div className="upload-field">
      <div
        className={`drop-area ${dragActive ? 'drag-active' : ''}`}
        onClick={() => inputRef.current?.click()}
        onDragOver={(event) => {
          event.preventDefault();
          setDragActive(true);
        }}
        onDragLeave={() => setDragActive(false)}
        onDrop={handleDrop}
      >
        <motion.div
          className="drop-content"
          whileHover={{ y: -4 }}
          transition={{ duration: 0.2 }}
        >
          {preview ? (
            <img className="preview-image" src={preview} alt="Selected preview" />
          ) : (
            <div className="drop-placeholder">
              <strong>Drag & drop or browse</strong>
              <span>Upload a cow or buffalo image.</span>
            </div>
          )}
        </motion.div>
      </div>

      {preview && (
        <div className="preview-actions">
          <span>{fileName}</span>
          <button type="button" className="ghost-button" onClick={onRemove}>
            Remove
          </button>
        </div>
      )}

      {error && <div className="field-error">{error}</div>}

      <button
        type="button"
        className="primary-button"
        onClick={onSubmit}
        disabled={!preview || isLoading}
      >
        {isLoading ? 'Analyzing image…' : 'Run classification'}
      </button>

      <input
        ref={inputRef}
        type="file"
        accept="image/*"
        className="file-input"
        onChange={handleChange}
      />
    </div>
  );
}
